int open_device(struct device *dev)
{
	int err;

	err = device_lock(dev);
	if (err == 0) {
		err = device_power_on(dev);
		if (err == 0) {
			err = device_init(dev);
			if (err != 0) {
				device_power_off(dev);
				device_unlock(dev);
			}
		} else {
			device_unlock(dev);
		}
	}
	return err;
}
